namespace sv_9eee862cf2e44e6a80e8828b91b633f8.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Reusable message input: textarea + send/reply button *@

<div class="message-input d-flex gap-2 p-2 border-top">
    <textarea class="form-control" rows="2" placeholder="@Placeholder"
              @bind="text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="btn btn-primary align-self-end" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string text = string.Empty;

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var content = text.Trim();
        text = string.Empty;
        await OnSend.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }
}

@* Quick emoji picker popup with common reactions *@

<div class="emoji-picker bg-white border rounded shadow-sm p-1 d-flex gap-1">
    @foreach (var emoji in Emojis)
    {
        <button class="btn btn-sm btn-light" @onclick="() => Pick(emoji)" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] Emojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    private async Task Pick(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

@* Row of reaction emoji badges *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

@if (Reactions?.Count > 0)
{
    <div class="reaction-bar d-flex gap-1 mt-1 flex-wrap">
        @foreach (var reaction in Reactions)
        {
            <span class="badge bg-light text-dark border" role="button"
                  title="@string.Join(", ", reaction.Users)"
                  @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)">
                @reaction.Emoji @reaction.Users.Count
            </span>
        }
    </div>
}

@code {
    [Parameter] public List<Reaction>? Reactions { get; set; }
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

@* Single message with author, timestamp, content, reactions, and hover actions *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

<div class="message-item p-2 rounded position-relative @(IsThreadRoot ? "border-start border-primary border-3" : "")"
     @onmouseenter="() => showActions = true" @onmouseleave="OnMouseLeave">
    <div class="d-flex justify-content-between align-items-baseline">
        <div>
            <strong class="me-2">@Message.Author</strong>
            <small class="text-muted" title="@Message.SentAt.ToString("g")">@FormatRelativeTime(Message.SentAt)</small>
        </div>
        @if (showActions)
        {
            <div class="message-actions d-flex gap-1">
                <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)" title="Reply">
                    💬
                </button>
                <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="ToggleEmojiPicker" title="React">
                    😀
                </button>
            </div>
        }
    </div>

    <div class="message-content mt-1">@Message.Content</div>

    <ReactionBar Reactions="@Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (ReplyCount > 0)
    {
        <button class="btn btn-sm btn-link p-0 mt-1" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showEmojiPicker)
    {
        <div class="position-absolute end-0" style="top: -2.5rem; z-index: 10;">
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool IsThreadRoot { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

@* Scrollable list of messages with load-more on scroll-to-top *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list flex-grow-1 overflow-auto d-flex flex-column" @ref="scrollContainer" id="@containerId">
    @if (IsLoadingMore)
    {
        <div class="text-center p-2">
            <div class="spinner-border spinner-border-sm text-secondary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }

    @if (HasMoreMessages)
    {
        <button class="btn btn-sm btn-link align-self-center" @onclick="() => OnLoadMore.InvokeAsync()">
            Load older messages
        </button>
    }

    @foreach (var msg in Messages)
    {
        <MessageItem Message="@msg"
                     ReplyCount="@GetReplyCount(msg.Id)"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />
    }
    <div @ref="bottomAnchor"></div>
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private ElementReference scrollContainer;
    private ElementReference bottomAnchor;
    private string containerId = $"msg-list-{Guid.NewGuid():N}";
    private IJSObjectReference? module;
    private bool shouldScrollToBottom = true;
    private int lastMessageCount;

    private int GetReplyCount(int messageId)
    {
        if (ThreadSummaries is null) return 0;
        return ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-9eee862cf2e44e6a80e8828b91b633f8/chat-scroll.js");
        }

        // Scroll to bottom when new messages arrive
        if (shouldScrollToBottom && Messages.Count != lastMessageCount)
        {
            lastMessageCount = Messages.Count;
            if (module is not null)
            {
                await module.InvokeVoidAsync("scrollToBottom", containerId);
            }
        }
    }

    public void SuppressAutoScroll() => shouldScrollToBottom = false;
    public void EnableAutoScroll() => shouldScrollToBottom = true;

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

@* Single channel entry in the sidebar *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

<div class="channel-item d-flex justify-content-between align-items-center p-2 rounded cursor-pointer @(IsActive ? "bg-primary text-white" : "hover-bg-light")"
     role="button" @onclick="() => OnClick.InvokeAsync(Channel.Id)">
    <div class="text-truncate me-2">
        <div class="fw-semibold">
            <span class="opacity-75">#</span> @Channel.Name
        </div>
        <small class="@(IsActive ? "text-white-50" : "text-muted") text-truncate d-block" style="font-size: 0.75rem;">
            @Channel.Description
        </small>
    </div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="badge rounded-pill @(IsActive ? "bg-white text-primary" : "bg-primary")">
            @Channel.UnreadCount
        </span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnClick { get; set; }
}

@* Left sidebar with channel list *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

<div class="channel-sidebar d-flex flex-column h-100 bg-dark text-white">
    <div class="p-3 border-bottom border-secondary">
        <h5 class="mb-0 fw-bold">💬 Channels</h5>
    </div>
    <div class="flex-grow-1 overflow-auto p-2 d-flex flex-column gap-1">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="@channel"
                         IsActive="@(channel.Id == SelectedChannelId)"
                         OnClick="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@* Right collapsible thread panel *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

<div class="thread-panel d-flex flex-column h-100 border-start">
    <div class="p-3 border-bottom d-flex justify-content-between align-items-center bg-light">
        <h6 class="mb-0 fw-bold">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="p-2 border-bottom bg-light bg-opacity-50">
            <MessageItem Message="@RootMessage" IsThreadRoot="true" />
        </div>
    }

    <div class="flex-grow-1 overflow-auto p-2 d-flex flex-column gap-1">
        @foreach (var reply in Replies)
        {
            <MessageItem Message="@reply" OnReactionAdded="OnReactionAdded" />
        }
    </div>

    <MessageInput Placeholder="Reply in thread…" ButtonLabel="Reply" OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

@* Main message area with header, message list, and input *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

<div class="message-area d-flex flex-column h-100">
    @if (ChannelName is not null)
    {
