@* Row of reaction emoji badges *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

@if (Reactions?.Count > 0)
{
    <div class="reaction-bar d-flex gap-1 mt-1 flex-wrap">
        @foreach (var reaction in Reactions)
        {
            <span class="badge bg-light text-dark border" role="button"
                  title="@string.Join(", ", reaction.Users)"
                  @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)">
                @reaction.Emoji @reaction.Users.Count
            </span>
        }
    </div>
}

@code {
    [Parameter] public List<Reaction>? Reactions { get; set; }
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

@* Single message with author, timestamp, content, reactions, and hover actions *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services

<div class="message-item p-2 rounded position-relative @(IsThreadRoot ? "border-start border-primary border-3" : "")"
     @onmouseenter="() => showActions = true" @onmouseleave="OnMouseLeave">
    <div class="d-flex justify-content-between align-items-baseline">
        <div>
            <strong class="me-2">@Message.Author</strong>
            <small class="text-muted" title="@Message.SentAt.ToString("g")">@FormatRelativeTime(Message.SentAt)</small>
        </div>
        @if (showActions)
        {
            <div class="message-actions d-flex gap-1">
                <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)" title="Reply">
                    💬
                </button>
                <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="ToggleEmojiPicker" title="React">
                    😀
                </button>
            </div>
        }
    </div>

    <div class="message-content mt-1">@Message.Content</div>

    <ReactionBar Reactions="@Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (ReplyCount > 0)
    {
        <button class="btn btn-sm btn-link p-0 mt-1" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showEmojiPicker)
    {
        <div class="position-absolute end-0" style="top: -2.5rem; z-index: 10;">
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool IsThreadRoot { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

