@* Scrollable list of messages with load-more on scroll-to-top *@
@using sv_9eee862cf2e44e6a80e8828b91b633f8.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list flex-grow-1 overflow-auto d-flex flex-column" @ref="scrollContainer" id="@containerId">
    @if (IsLoadingMore)
    {
        <div class="text-center p-2">
            <div class="spinner-border spinner-border-sm text-secondary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }

    @if (HasMoreMessages)
    {
        <button class="btn btn-sm btn-link align-self-center" @onclick="() => OnLoadMore.InvokeAsync()">
            Load older messages
        </button>
    }

    @foreach (var msg in Messages)
    {
        <MessageItem Message="@msg"
                     ReplyCount="@GetReplyCount(msg.Id)"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />
    }
    <div @ref="bottomAnchor"></div>
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private ElementReference scrollContainer;
    private ElementReference bottomAnchor;
    private string containerId = $"msg-list-{Guid.NewGuid():N}";
    private IJSObjectReference? module;
    private bool shouldScrollToBottom = true;
    private int lastMessageCount;

    private int GetReplyCount(int messageId)
    {
        if (ThreadSummaries is null) return 0;
        return ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-9eee862cf2e44e6a80e8828b91b633f8/chat-scroll.js");
        }

        // Scroll to bottom when new messages arrive
        if (shouldScrollToBottom && Messages.Count != lastMessageCount)
        {
            lastMessageCount = Messages.Count;
            if (module is not null)
            {
                await module.InvokeVoidAsync("scrollToBottom", containerId);
            }
        }
    }

    public void SuppressAutoScroll() => shouldScrollToBottom = false;
    public void EnableAutoScroll() => shouldScrollToBottom = true;

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

