+                        SelectedChannelId="@selectedChannelId"
+                        OnChannelSelected="SelectChannel" />
+    </div>
+
+    @* Main message area — expands when thread is closed *@
+    <div class="chat-main" style="flex: 1; min-width: 0;">
+        <MessageArea ChannelName="@selectedChannel?.Name"
+                     ChannelDescription="@selectedChannel?.Description"
+                     Messages="@messages"
+                     ThreadSummaries="@threadSummaries"
+                     HasMoreMessages="@hasMoreMessages"
+                     IsLoadingMore="@isLoadingMore"
+                     OnLoadMore="LoadOlderMessages"
+                     OnSendMessage="SendMessage"
+                     OnReplyClicked="OpenThread"
+                     OnReactionAdded="AddReaction" />
+    </div>
+
+    @* Right thread panel — 25%, shown only when a thread is open *@
+    @if (threadRootMessage is not null)
+    {
+        <div class="chat-thread" style="width: 25%; min-width: 250px;">
+            <ThreadPanel RootMessage="@threadRootMessage"
+                         Replies="@threadReplies"
+                         OnClose="CloseThread"
+                         OnSendReply="SendThreadReply"
+                         OnReactionAdded="AddReaction" />
+        </div>
+    }
+</div>
+
+@code {
+    private const int PageSize = 30;
+
+    private List<Channel> channels = [];
+    private List<Message> messages = [];
+    private List<Message> threadReplies = [];
+    private Dictionary<int, ThreadSummary> threadSummaries = new();
+
+    private Channel? selectedChannel;
+    private int selectedChannelId;
+    private Message? threadRootMessage;
+
+    private bool hasMoreMessages;
+    private bool isLoadingMore;
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        selectedChannelId = channelId;
+        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
+        CloseThread();
+
+        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        hasMoreMessages = messages.Count >= PageSize;
+
+        await BuildThreadSummaries();
+        await ChatService.MarkChannelReadAsync(channelId);
+
+        // Update unread count locally
+        var idx = channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            channels[idx] = channels[idx] with { UnreadCount = 0 };
+        }
+    }
+
+    private async Task LoadOlderMessages()
+    {
+        if (isLoadingMore) return;
+        isLoadingMore = true;
+
+        var older = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);
+        hasMoreMessages = older.Count >= PageSize;
+
+        if (older.Count > 0)
+        {
+            messages.InsertRange(0, older);
+            await BuildThreadSummaries();
+        }
+
+        isLoadingMore = false;
+    }
+
+    private async Task SendMessage(string content)
+    {
+        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
+        messages.Add(msg);
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        if (threadRootMessage is null) return;
+
+        var allThread = await ChatService.GetThreadAsync(messageId);
+        threadReplies = allThread.Where(m => m.Id != messageId).ToList();
+    }
+
+    private void CloseThread()
+    {
+        threadRootMessage = null;
+        threadReplies = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (threadRootMessage is null) return;
+
+        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
+        threadReplies.Add(reply);
+
+        // Update thread summary
+        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
+            threadRootMessage.Id,
+            threadReplies.Count,
+            reply.SentAt
+        );
+    }
+
+    private async Task AddReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Optimistic UI update for main messages
+        UpdateReactionInList(messages, args.MessageId, args.Emoji);
+        UpdateReactionInList(threadReplies, args.MessageId, args.Emoji);
+    }
+
+    private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
+    {
+        var idx = list.FindIndex(m => m.Id == messageId);
+        if (idx < 0) return;
+
+        var msg = list[idx];
+        var reactions = msg.Reactions.ToList();
+        var existing = reactions.FindIndex(r => r.Emoji == emoji);
+        if (existing >= 0)
+        {
+            var r = reactions[existing];
+            reactions[existing] = r with { Users = [..r.Users, "You"] };
+        }
+        else
+        {
+            reactions.Add(new Reaction(emoji, ["You"]));
+        }
+        list[idx] = msg with { Reactions = reactions };
+    }
+
+    private async Task BuildThreadSummaries()
+    {
+        threadSummaries.Clear();
+        // Identify thread root messages (those with replies referencing them)
+        var rootIds = messages
+            .Where(m => m.ReplyToId is not null)
+            .Select(m => m.ReplyToId!.Value)
+            .Distinct();
+
+        foreach (var rootId in rootIds)
+        {
+            try
+            {
+                var thread = await ChatService.GetThreadAsync(rootId);
+                var replies = thread.Where(m => m.Id != rootId).ToList();
+                if (replies.Count > 0)
+                {
+                    threadSummaries[rootId] = new ThreadSummary(
+                        rootId,
+                        replies.Count,
+                        replies.Max(r => r.SentAt)
+                    );
+                }
+            }
+            catch
+            {
+                // Thread may not exist yet
+            }
+        }
+    }
+}
